import React, { useState } from 'react';
import { FiMail, FiLock, FiBriefcase, FiUser, FiTruck } from 'react-icons/fi'; 

const Login = () => {
  const [userRole, setUserRole] = useState('customer'); 

  return (
    <div className="d-flex align-items-center justify-content-center min-vh-100" style={{
      backgroundImage: `linear-gradient(rgba(0,0,0,0.6), rgba(0,0,0,0.6)), url('https://images.unsplash.com/photo-1519003722824-192d99a24bb5?q=80&w=2000')`,
      backgroundSize: 'cover',
      backgroundPosition: 'center',
    }}>
      <div className="card shadow-lg p-4 rounded-4 border-0" style={{ width: '420px', backgroundColor: 'rgba(255, 255, 255, 0.95)' }}>
        <h2 className="text-center fw-bold text-primary mb-2">Apni Manzil</h2>
        <p className="text-center text-muted small mb-4">Logistics Aggregator Portal</p>
        
        <div className="btn-group w-100 mb-4 shadow-sm p-1 bg-light rounded-pill">
          <button className={`btn rounded-pill small ${userRole === 'customer' ? 'btn-primary' : 'text-dark'}`} onClick={() => setUserRole('customer')}><FiUser /> User</button>
          <button className={`btn rounded-pill small ${userRole === 'business' ? 'btn-primary' : 'text-dark'}`} onClick={() => setUserRole('business')}><FiBriefcase /> MSME</button>
          <button className={`btn rounded-pill small ${userRole === 'transporter' ? 'btn-primary' : 'text-dark'}`} onClick={() => setUserRole('transporter')}><FiTruck /> Partner</button>
        </div>

        <form>
          <div className="mb-3">
            <label className="small fw-bold text-muted">Email / Phone</label>
            <div className="input-group border-bottom"><span className="input-group-text bg-transparent border-0"><FiMail /></span>
              <input type="text" className="form-control border-0 bg-transparent" placeholder="Enter details" />
            </div>
          </div>
          <div className="mb-4">
            <label className="small fw-bold text-muted">Password</label>
            <div className="input-group border-bottom"><span className="input-group-text bg-transparent border-0"><FiLock /></span>
              <input type="password" className="form-control border-0 bg-transparent" placeholder="••••••••" />
            </div>
          </div>
          <button className="btn btn-primary w-100 py-2 rounded-pill fw-bold shadow">Login as {userRole}</button>
        </form>
      </div>
    </div>
  );
};

export default Login;
